-- ⚠️ Superseded by fix-garden-taxonomy-v2.sql (A1–A13 ingredient-led subs, 2026).
-- fix-garden-taxonomy.sql
-- Garden & Earth taxonomy (category 3). Keeps dishes/recipes table content; deactivates legacy Vegetables/Fruits placeholders.
-- Generated by database/taxonomy/generate_taxonomy_sql.py — safe to re-run.

-- ── Garden & Earth ─────────────────────────────────────────────────────────────

UPDATE public.recipe_subcategories SET is_active = false
WHERE category = 'Garden & Earth'
  AND name IN ('Vegetables', 'Fruits', 'Herbs & Greens', 'Legumes & Pulses');

UPDATE public.recipe_subcategories SET is_active = false
WHERE category = 'Garden & Earth'
  AND name NOT IN ('Thoran & Stir-Fries (Coconut-Based)', 'Mezhukkupuratti (Stir-Fried in Oil)', 'Poriyal & Varuval (Tamil Style)', 'North Indian Dry Sabzis', 'Other Regional Dry Dishes', 'Leafy Green Stir-Fries', 'Root Vegetable & Firm Veg Stir-Fries', 'Tofu Stir-Fries', 'Mixed Vegetable Stir-Fries', 'Bean Sprout & Mushroom Dishes', 'Filipino & South-East Asian Vegetable Dishes', 'Roasted Vegetable Dishes', 'Pan-Cooked Mediterranean Dishes', 'Stuffed Vegetables (Dry / Baked)', 'Roasted Vegetables', 'Sauteed & Pan-Fried Vegetables', 'Potato Dishes (Dry)', 'Indian Legume Stir-Fries', 'Sprouted & Cooked Legumes', 'Scrambled & Bhurji Style', 'Pan-Fried Egg Dishes');

ON CONFLICT (category, name) DO UPDATE SET
  sort_order = EXCLUDED.sort_order,
  is_active = EXCLUDED.is_active;

-- ── Divisions ─────────────────────────────────────────────────────────────────

ON CONFLICT (category, subcategory, name) DO UPDATE SET
  sort_order = EXCLUDED.sort_order,
  is_active = true,
  emoji = EXCLUDED.emoji,
  subtitle = EXCLUDED.subtitle,
  description = EXCLUDED.description;

-- ── Deactivate orphaned legacy divisions ───────────────────────────────────────

